      await waitFor(element(by.text('Treinos'))).toBeVisible().withTimeout(10000);
      await expect(element(by.text('Treinos'))).toBeVisible();
      return;
    }
    await waitFor(element(by.id('input-peso'))).toBeVisible().withTimeout(10000);
    await element(by.id('input-peso')).tap();
    await element(by.id('input-peso')).clearText();
    await element(by.id('input-peso')).typeText('82');
    await expect(element(by.id('input-peso'))).toHaveText('82');
    await element(by.id('input-peso-meta')).tap();
    await element(by.id('input-peso-meta')).clearText();
    await element(by.id('input-peso-meta')).typeText('77');
    await expect(element(by.id('input-peso-meta'))).toHaveText('77');
    await element(by.id('input-altura')).tap();
    await element(by.id('input-altura')).clearText();
    await element(by.id('input-altura')).typeText('178');
    await expect(element(by.id('input-altura'))).toHaveText('178');
    await device.pressBack();
    for (let attempt = 0; attempt < 6; attempt += 1) {
      const visible = await isVisible(by.id('btn-questionario-continuar'), 600);
      if (visible) {
        break;
      }
      await element(by.type('com.facebook.react.views.scroll.ReactScrollView')).atIndex(0).swipe('up', 'fast', 0.8);
    }
    await element(by.id('btn-questionario-continuar')).tap();
    const navigatedOnFirstTap = await isVisible(by.text('Treinos'), 5000);
    if (!navigatedOnFirstTap) {
      await element(by.id('btn-questionario-continuar')).tap();
    }
    await waitFor(element(by.text('Treinos'))).toBeVisible().withTimeout(15000);
    await expect(element(by.text('Treinos'))).toBeVisible();
  }

